// Example Usage (Client Code)
public class ExamClient {
    public static void main(String[] args) {
        List<Exam> exams = List.of(
                new OpenExam("Math Midterm"),
                new MixedExam("Physics Final"),
                new ScrambledExam("Chemistry Quiz")
